39	function resolveConfiguredDefaultNostrAccountId(cfg: OpenClawConfig): string | undefined {
40	  const nostrCfg = (cfg.channels as Record<string, unknown> | undefined)?.nostr as
41	    | NostrAccountConfig
42	    | undefined;
43	  return normalizeOptionalAccountId(nostrCfg?.defaultAccount);
44	}
45	
46	/**
47	 * List all configured Nostr account IDs
48	 */
49	export function listNostrAccountIds(cfg: OpenClawConfig): string[] {
50	  const nostrCfg = (cfg.channels as Record<string, unknown> | undefined)?.nostr as
51	    | NostrAccountConfig
52	    | undefined;
53	  const privateKey = normalizeSecretInputString(nostrCfg?.privateKey);
54	  return listCombinedAccountIds({
55	    configuredAccountIds: [],
56	    implicitAccountId: privateKey
