46	function normalizeNostrAllowEntry(entry: string): string | "*" | null {
47	  const trimmed = entry.trim();
48	  if (!trimmed) {
49	    return null;
50	  }
51	  if (trimmed === "*") {
52	    return "*";
53	  }
54	  try {
55	    return normalizePubkey(trimmed.replace(/^nostr:/i, ""));
56	  } catch {
57	    return null;
58	  }
59	}
