```

**Key decisions:**
- Minimal `configSchema` with no properties, matching the Nostr pattern exactly.

---

#### File 3: `extensions/pulseboard/src/types.ts`

**Purpose:** TypeScript interfaces for the PulseBoard account, config, and message types. Account resolution functions.

**Pattern source:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386421801-063iqb/extensions/nostr/src/types.ts`

**Content:**
```typescript
import {
  DEFAULT_ACCOUNT_ID,
  normalizeAccountId,
  normalizeOptionalAccountId,
} from "openclaw/plugin-sdk/account-id";
import {
  listCombinedAccountIds,
  resolveListedDefaultAccountId,
} from "openclaw/plugin-sdk/account-resolution";
import type { OpenClawConfig } from "openclaw/plugin-sdk/core";

export interface PulseBoardAccountConfig {
  enabled?: boolean;
  name?: string;
  defaultAccount?: string;
  apiKey?: string;
  dmPolicy?: "pairing" | "allowlist" | "open" | "disabled";
  allowFrom?: Array<string | number>;
}

export interface ResolvedPulseBoardAccount {
  accountId: string;
  name?: string;
  enabled: boolean;
  configured: boolean;
  apiKey: string;
  config: PulseBoardAccountConfig;
}

export interface PulseBoardMessage {
  id: string;
  from: string;
  text: string;
  timestamp: number;
}

function resolveConfiguredDefaultPulseBoardAccountId(
  cfg: OpenClawConfig,
): string | undefined {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;
  return normalizeOptionalAccountId(pbCfg?.defaultAccount);
}

export function listPulseBoardAccountIds(cfg: OpenClawConfig): string[] {
  const pbCfg = (cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;
  const apiKey = pbCfg?.apiKey?.trim() ?? "";
  return listCombinedAccountIds({
    configuredAccountIds: [],
    implicitAccountId: apiKey
      ? (resolveConfiguredDefaultPulseBoardAccountId(cfg) ?? DEFAULT_ACCOUNT_ID)
      : undefined,
  });
}

export function resolveDefaultPulseBoardAccountId(
  cfg: OpenClawConfig,
): string {
  return resolveListedDefaultAccountId({
    accountIds: listPulseBoardAccountIds(cfg),
    configuredDefaultAccountId:
      resolveConfiguredDefaultPulseBoardAccountId(cfg),
  });
}

export function resolvePulseBoardAccount(opts: {
  cfg: OpenClawConfig;
  accountId?: string | null;
}): ResolvedPulseBoardAccount {
  const accountId = normalizeAccountId(
    opts.accountId ?? resolveDefaultPulseBoardAccountId(opts.cfg),
  );
  const pbCfg = (opts.cfg.channels as Record<string, unknown> | undefined)
    ?.pulseboard as PulseBoardAccountConfig | undefined;

  const apiKey = pbCfg?.apiKey?.trim() ?? "";
  const configured = Boolean(apiKey);

  return {
    accountId,
    name: pbCfg?.name?.trim() || undefined,
    enabled: pbCfg?.enabled !== false,
    configured,
    apiKey,
    config: {
      enabled: pbCfg?.enabled,
      name: pbCfg?.name,
      apiKey: pbCfg?.apiKey,
      dmPolicy: pbCfg?.dmPolicy,
      allowFrom: pbCfg?.allowFrom,
    },
  };
}
```

**Key decisions:**
- Uses the same pattern as Nostr: reads from `cfg.channels.pulseboard` top-level config section.
- Uses `apiKey` as the simple "is configured" sentinel (analogous to Nostr's `privateKey`).
- `PulseBoardMessage` is a simple stub interface for future use.
- Imports `OpenClawConfig` from `openclaw/plugin-sdk/core` (this is where the Nostr plugin's `runtime-api.ts` re-exports it from, but for PulseBoard we can import it directly from the SDK since it is re-exported by `openclaw/plugin-sdk/core`).

---

#### File 4: `extensions/pulseboard/src/runtime.ts`

**Purpose:** Mutable runtime store for the PulseBoard plugin.

**Pattern source:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386421801-063iqb/extensions/nostr/src/runtime.ts`

**Content:**
```typescript
import { createPluginRuntimeStore } from "openclaw/plugin-sdk/runtime-store";
import type { PluginRuntime } from "openclaw/plugin-sdk/runtime-store";

const {
  setRuntime: setPulseBoardRuntime,
  getRuntime: getPulseBoardRuntime,
} = createPluginRuntimeStore<PluginRuntime>(
  "PulseBoard runtime not initialized",
);

export { getPulseBoardRuntime, setPulseBoardRuntime };
```

**Key decisions:**
- Unlike Nostr which imports `PluginRuntime` from `../api.js` (which re-exports from `openclaw/plugin-sdk/nostr`), PulseBoard imports directly from `openclaw/plugin-sdk/runtime-store` since there is no `openclaw/plugin-sdk/pulseboard` facade.
- This is the critical deviation noted in the requirements. `PluginRuntime` is exported from `src/plugin-sdk/runtime-store.ts` at line 1: `export type { PluginRuntime } from "../plugins/runtime/types.js";`.

---

#### File 5: `extensions/pulseboard/src/channel.ts`

**Purpose:** The core channel plugin definition using `createChatChannelPlugin`.

**Pattern source:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386421801-063iqb/extensions/nostr/src/channel.ts`

**Content:**
```typescript
import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import {
  createChatChannelPlugin,
  DEFAULT_ACCOUNT_ID,
  formatPairingApproveHint,
  type ChannelPlugin,
} from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import { createOptionalChannelSetupSurface } from "openclaw/plugin-sdk/channel-setup";
import { getPulseBoardRuntime } from "./runtime.js";
import {
  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

const { setupAdapter: pulseBoardSetupAdapter, setupWizard: pulseBoardSetupWizard } =
  createOptionalChannelSetupSurface({
    channel: "pulseboard",
    label: "PulseBoard",
    npmSpec: "@openclaw/pulseboard",
    docsPath: "/channels/pulseboard",
  });

const resolvePulseBoardDmPolicy =
  createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
    channelKey: "pulseboard",
    resolvePolicy: (account) => account.config.dmPolicy,
    resolveAllowFrom: (account) => account.config.allowFrom,
    policyPathSuffix: "dmPolicy",
    defaultPolicy: "pairing",
    approveHint: formatPairingApproveHint("pulseboard"),
  });

const pulseBoardConfigAdapter =
  createTopLevelChannelConfigAdapter<ResolvedPulseBoardAccount>({
    sectionKey: "pulseboard",
    resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
    listAccountIds: listPulseBoardAccountIds,
    defaultAccountId: resolveDefaultPulseBoardAccountId,
    deleteMode: "clear-fields",
    clearBaseFields: [
      "name",
      "defaultAccount",
      "apiKey",
      "dmPolicy",
      "allowFrom",
    ],
    resolveAllowFrom: (account) => account.config.allowFrom,
  });

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Fictional stub channel for testing and development.",
        order: 99,
      },
      capabilities: {
        chatTypes: ["direct"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
          }),
      },
      messaging: {
        normalizeTarget: (target) => target.trim().toLowerCase(),
        targetResolver: {
          looksLikeId: (input) => /^pb-[a-z0-9]+$/i.test(input.trim()),
          hint: "<pb-userid>",
        },
      },
      status: {
        ...createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
          buildChannelSummary: ({ snapshot }) =>
            buildPassiveChannelStatusSummary(snapshot, {}),
          resolveAccountSnapshot: ({ account }) => ({
            accountId: account.accountId,
            name: account.name,
            enabled: account.enabled,
            configured: account.configured,
          }),
        }),
      },
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (stub)`,
          );

          if (!account.configured) {
            throw new Error("PulseBoard API key not configured");
          }

          return {
            stop: () => {
              ctx.log?.info(
                `[${account.accountId}] PulseBoard provider stopped`,
              );
            },
          };
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUserId",
        message: "Your pairing request has been approved!",
        notify: async () => {
          // Stub: no-op notification
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ to }) => {
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pb-${Date.now()}`,
        });
      },
    },
  });
```

**Key decisions:**
- **Inline `meta` object** rather than `getChatChannelMeta("pulseboard")` since `getChatChannelMeta` only accepts the known `ChatChannelId` union (`telegram | whatsapp | discord | irc | googlechat | slack | signal | imessage | line`). This matches how the Nostr plugin does it.
- Uses `createOptionalChannelSetupSurface` from `openclaw/plugin-sdk/channel-setup` to produce the setup adapter and wizard, matching the Nostr pattern.
- `createComputedAccountStatusAdapter` does not require the `defaultRuntime` or `collectStatusIssues` parameters (they are optional in the more minimal stub case). However, if the build requires them, they can be added. Looking at the Nostr reference, it passes `defaultRuntime` and `collectStatusIssues`, but for a stub that never truly starts a gateway, omitting them simplifies things.
- `sendText` is a pure stub -- it returns a synthetic `messageId` with the `attachChannelToResult` wrapper, never touching a real network.
- Gateway's `startAccount` is a stub that validates the API key is present and returns a no-op `stop()`.
- Messaging uses a simple `pb-*` format for user IDs.

---

#### File 6: `extensions/pulseboard/index.ts`

**Purpose:** Main plugin entry point that defines the channel plugin entry.

**Pattern source:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386421801-063iqb/extensions/nostr/index.ts`

**Content:**
```typescript
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
