import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin, type ChannelPlugin } from "openclaw/plugin-sdk/core";

// Minimal resolved account shape required by createChatChannelPlugin.
// The generic constraint is { accountId?: string | null }.
interface ResolvedPulseBoardAccount {
  accountId: string;
  configured: boolean;
}

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",

      // Inline meta — getChatChannelMeta only accepts a closed union of known
      // channel IDs and "pulseboard" is not in that union.
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        docsPath: "/channels/pulseboard",
        blurb: "Connect to PulseBoard bulletin messaging.",
      },

      capabilities: {
        chatTypes: ["direct", "group"],
        media: false,
      },

      reload: { configPrefixes: ["channels.pulseboard"] },

      // Minimal config adapter with account resolution stubs
      config: {
        listAccountIds: () => ["default"],
        resolveAccount: (_cfg, accountId) => ({
          accountId: accountId ?? "default",
          configured: false,
        }),
        isConfigured: (account) => account.configured,
      },

      // Setup adapter stub with required applyAccountConfig
      setup: {
        applyAccountConfig: (params) => params.cfg,
      },

      // Gateway adapter — async stub that logs connection
      gateway: {
        startAccount: async (ctx) => {
          ctx.log?.info(
            `[${ctx.account.accountId}] starting PulseBoard connection (stub)`,
          );
          return {
            stop: () => {
              ctx.log?.info(
                `[${ctx.account.accountId}] PulseBoard connection stopped`,
              );
            },
          };
        },
      },

      // Messaging adapter — normalizeTarget trims whitespace
      messaging: {
        normalizeTarget: (target) => target.trim(),
      },
    },

    // Outbound adapter (flat form, same as Nostr pattern)
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ to }) => {
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pb-${Date.now()}`,
        });
      },
    },
  });

